public function generatePDF(FacturaElectronica $facturaElectronica)
    {

        /** @var Afip $afip */
        $afip = $this->buildAfipSDKCliente();

        // Nombre para el archivo (sin .pdf)
        $name = $facturaElectronica->getNumeroComprobante();

        // Opciones para el archivo
        $options = array(
            "width" => 8, // Ancho de pagina en pulgadas. Usar 3.1 para ticket
            "marginLeft" => 0.4, // Margen izquierdo en pulgadas. Usar 0.1 para ticket 
            "marginRight" => 0.4, // Margen derecho en pulgadas. Usar 0.1 para ticket 
            "marginTop" => 0.4, // Margen superior en pulgadas. Usar 0.1 para ticket 
            "marginBottom" => 0.4 // Margen inferior en pulgadas. Usar 0.1 para ticket 
        );

        // Creamos el PDF
        $res = $afip->ElectronicBilling->CreatePDF(array(
            "html" => $this->buildHTML($facturaElectronica),
            "file_name" => $name,
            "options" => $options
        ));

        // Debug::dump($res, 'Response de $afip->ElectronicBilling->CreatePDF');
        // Descargamos el PDF y lo guardamos en el servidor
        $this->downloadRemotePDF($facturaElectronica, $res['file'], true);
    }
